5888: 	     are local to a function will be fixed in
5889: 	     decls_for_scope.  */
5890: 	  && (!RECORD_OR_UNION_TYPE_P (t)
5891: 	      || !TYPE_CONTEXT (t)
5892: 	      || TREE_CODE (TYPE_CONTEXT (t)) != FUNCTION_DECL)
